<script setup lang="ts">
import { useBacktestApi } from '@/composables/useBacktestApi';

enum BtRunModes {
  run = 'run',
  results = 'results',
  visualize = 'visualize',
  visualizesummary = 'visualize-summary',
  compareresults = 'compare-results',
  historicresults = 'historicResults',
}

const bt = reactive(useBacktestApi());
const btStore = useBtStore();

const hasBacktestResult = computed(() => Object.keys(bt.backtestHistory).length !== 0);
const hasMultiBacktestResult = computed(() => Object.keys(bt.backtestHistory).length > 1);

const timeframe = computed((): string => {
  return bt.selectedBacktestResult?.timeframe ?? '';
});

const showLeftBar = ref(false);

const btFormMode = ref<BtRunModes>(BtRunModes.run);
const pollInterval = ref<number | null>(null);

function selectBacktestResult() {
  const r = bt.selectedBacktestResult;
  if (!r) return;
  btStore.strategy = r.strategy_name || '';
  if (btStore.strategy) bt.getStrategy(btStore.strategy).catch(() => {});
  btStore.selectedTimeframe = r.timeframe || '';
  btStore.selectedDetailTimeframe = r.timeframe_detail || '';
  btStore.timerange = r.timerange || '';
  btStore.enableProtections = r.enable_protections || false;
  btStore.freqAI.enabled = !!r.freqaimodel;
  btStore.freqAI.model = r.freqaimodel || '';
  btStore.freqAI.identifier = r.freqai_identifier || '';
  btFormMode.value = BtRunModes.results;
}

watch(
  () => bt.selectedBacktestResultKey,
  () => {
    selectBacktestResult();
  },
);

onMounted(async () => {
  await bt.getState();
  // Also poll immediately to pick up any running/completed backtest
  bt.pollBacktest();
});
watch(
  () => bt.backtestRunning,
  (running) => {
    if (running) {
      pollInterval.value = window.setInterval(bt.pollBacktest, 1000);
    } else if (pollInterval.value) {
      clearInterval(pollInterval.value);
      pollInterval.value = null;
    }
  },
);
</script>

<template>
  <div class="backtest-container flex flex-row pt-1 me-1" style="height: calc(100vh - 60px)">
    <div class="flex flex-col w-full">
      <h2 class="ms-5 text-3xl font-bold">Backtesting</h2>
      <p v-if="!bt.canRunBacktest" class="text-sm text-surface-400 ms-5">
        Switch to the Backtest bot in the top-right dropdown to run backtests.
      </p>
      <div class="w-full">
        <Tabs v-model:value="btFormMode" lazy>
          <TabList>
            <Tab
              v-if="bt.botFeatures.backtestHistory"
              class="flex items-center"
              value="historicResults"
              :disabled="!bt.canRunBacktest"
              ><i-lucide-cloud-download class="me-2" />Load Results</Tab
            >
            <Tab
              class="flex items-center"
              value="run"
              :disabled="!bt.canRunBacktest"
              ><i-lucide-zap class="me-2" />Run backtest</Tab
            >
            <Tab
              id="bt-analyze-btn"
              class="flex items-center"
              value="results"
              :disabled="!hasBacktestResult"
              ><i-lucide-table-2 class="me-2" />Analyze result</Tab
            >
            <Tab
              v-if="hasMultiBacktestResult"
              class="flex items-center"
              value="compare-results"
              :disabled="!hasMultiBacktestResult"
              ><i-lucide-git-compare class="me-2" />Compare results</Tab
            >
            <Tab class="flex items-center" value="visualize-summary" :disabled="!hasBacktestResult"
              ><i-lucide-bar-chart-2 class="me-2" />Visualize summary</Tab
            >
            <Tab class="flex items-center" value="visualize" :disabled="!hasBacktestResult"
              ><i-lucide-line-chart class="me-2" />Visualize result</Tab
            >
          </TabList>
          <TabPanels>
            <TabPanel value="historicResults">
              <BacktestHistoryLoad />
            </TabPanel>
            <TabPanel value="run">
              <BacktestRun />
            </TabPanel>
            <TabPanel value="results">
              <BacktestResultAnalysis
                v-if="hasBacktestResult && bt.selectedBacktestResult"
                :backtest-result="bt.selectedBacktestResult"
                class="flex-fill"
              />
            </TabPanel>
            <TabPanel value="compare-results">
              <BacktestResultComparison
                v-if="hasMultiBacktestResult"
                :backtest-results="bt.backtestHistory"
                class="flex-fill"
              />
            </TabPanel>
            <TabPanel value="visualize-summary">
              <BacktestGraphs
                v-if="hasBacktestResult && bt.selectedBacktestResult"
                :trades="bt.selectedBacktestResult.trades"
                class="flex-fill"
              />
            </TabPanel>
            <TabPanel value="visualize" l>
              <BacktestResultChart
                v-if="bt.selectedBacktestResult"
                :timeframe="timeframe"
                :strategy="btStore.strategy"
                :timerange="btStore.timerange"
                :backtest-result="bt.selectedBacktestResult"
                :freqai-model="btStore.freqAI.enabled ? btStore.freqAI.model : undefined"
              />
            </TabPanel>
          </TabPanels>
        </Tabs>

        <small v-show="bt.backtestRunning" class="text-end bt-running-label"
          >Backtest running: {{ bt.backtestStep }}
          {{ formatPercent(bt.backtestProgress, 2) }}</small
        >
      </div>
    </div>
  </div>
</template>

