<script setup lang="ts">
import type { MsgBoxObject } from '@/components/general/MessageBox.vue';
import MessageBox from '@/components/general/MessageBox.vue';

import type { BacktestHistoryEntry } from '@/types';
import { useBacktestApi } from '@/composables/useBacktestApi';
import axios from 'axios';

const botStore = useBotStore();
const bt = reactive(useBacktestApi());
const msgBox = ref<typeof MessageBox>();
const historyList = computed(() => bt.backtestHistoryList);
const filterText = ref('');
const filterTextDebounced = refDebounced(filterText, 350, { maxWait: 1000 });

// PB enrichment
const pbMeta = ref<Record<string, any>>({});

async function fetchPbMeta() {
  try {
    const res = await axios.get('/v1/trade/backtest/pb-results', { withCredentials: true });
    const items = res.data?.items || res.data || [];
    const map: Record<string, any> = {};
    for (const r of items) {
      if (r.filename) map[r.filename] = r;
    }
    pbMeta.value = map;
  } catch { /* best-effort */ }
}

onMounted(() => {
  bt.getBacktestHistory();
  fetchPbMeta();
});

function deleteBacktestResult(result: BacktestHistoryEntry) {
  const msg: MsgBoxObject = {
    title: 'Delete result',
    message: `Delete result ${result.filename} from disk?`,
    accept: () => { bt.deleteBacktestHistoryResult(result); },
  };
  msgBox.value?.show(msg);
}

// Merge freqtrade history with PB metrics into flat sortable rows
const mergedList = computed(() =>
  bt.backtestHistoryList.map((r) => {
    const p = pbMeta.value[r.filename] || {};
    return {
      ...r,
      _version: p.version || '',
      _mode: p.trading_mode || '',
      _from: r.backtest_start_ts ? new Date(r.backtest_start_ts * 1000).toISOString().slice(0, 10) : '',
      _to: r.backtest_end_ts ? new Date(r.backtest_end_ts * 1000).toISOString().slice(0, 10) : '',
      _trades: p.total_trades ?? null,
      _wins: p.wins ?? null,
      _losses: p.losses ?? null,
      _winrate: p.winrate ?? null,
      _profit: p.profit_total_abs ?? null,
      _profitPct: p.profit_total_pct ?? null,
      _dd: p.max_drawdown_abs ?? null,
      _ddPct: p.max_drawdown_pct ?? null,
      _sharpe: p.sharpe ?? null,
      _sortino: p.sortino ?? null,
      _calmar: p.calmar ?? null,
      _pf: p.profit_factor ?? null,
      _dur: p.avg_duration || '',
      _pairs: p.pairs_count ?? null,
      _notes: p.notes || r.notes || '',
      _cagr: (() => {
        const pct = p.profit_total_pct;
        const startTs = r.backtest_start_ts;
        const endTs = r.backtest_end_ts;
        if (pct == null || !startTs || !endTs || endTs <= startTs) return null;
        const years = (endTs - startTs) / (365.25 * 86400);
        if (years < 0.01) return null;
        return Math.pow(1 + Number(pct), 1 / years) - 1;
      })(),
    };
  }),
);

const filteredList = computed(() =>
  mergedList.value.filter((r) =>
    r.filename.toLowerCase().includes(filterTextDebounced.value.toLowerCase()) ||
    r.strategy.toLowerCase().includes(filterTextDebounced.value.toLowerCase()),
  ),
);

function rowClick(row: any) {
  bt.getBacktestHistoryResult(row.data);
}

function pb(filename: string) {
  return pbMeta.value[filename] || {};
}

// Inline edit notes — save to PB
const editingNoteId = ref<string>('');
const editingNoteText = ref('');

function startEditNote(filename: string, currentNote: string) {
  editingNoteId.value = filename;
  editingNoteText.value = currentNote || '';
}

async function saveNote(filename: string) {
  const p = pbMeta.value[filename];
  if (!p?.id) { editingNoteId.value = ''; return; }
  try {
    await axios.patch(`/v1/trade/backtest/pb-results/${p.id}`, { notes: editingNoteText.value }, { withCredentials: true });
    p.notes = editingNoteText.value;
  } catch { /* best-effort */ }
  editingNoteId.value = '';
}

function fmtPct(v: any, sign = false): string {
  if (v == null || v === '') return '—';
  const n = Number(v) * 100;
  const prefix = sign ? (n >= 0 ? '+' : '') : '';
  return prefix + n.toFixed(1) + '%';
}
function fmtNum(v: any, d = 1): string {
  if (v == null || v === '') return '—';
  return Number(v).toFixed(d);
}
function fmtMoney(v: any, sign = true): string {
  if (v == null || v === '') return '—';
  const n = Number(v);
  const abs = Math.abs(n);
  const formatted = abs >= 1000 ? abs.toLocaleString('en-US', { maximumFractionDigits: 0 }) : abs.toFixed(0);
  if (sign) return (n >= 0 ? '+' : '-') + formatted;
  return (n < 0 ? '-' : '') + formatted;
}
function fmtComma(v: any): string {
  if (v == null || v === '') return '—';
  return Number(v).toLocaleString('en-US');
}

// Format date range from timestamps: "2024-03-24" style
function fmtDate(ts: number | undefined): string {
  if (!ts) return '—';
  const d = new Date(ts * 1000);
  return d.toISOString().slice(0, 10);
}

// Extract exchange and mode from PB or description
function getExchange(filename: string): string {
  const p = pb(filename);
  return p.exchange || '—';
}
function getMode(filename: string): string {
  const p = pb(filename);
  return p.trading_mode || '—';
}
</script>

<template>
  <div>
    <div class="flex items-center justify-between mb-2">
      <InputText
        v-if="historyList.length > 0"
        id="trade-filter"
        v-model="filterText"
        type="text"
        size="small"
        placeholder="Filter results"
        title="Filter results"
        style="width: 200px"
      />
      <Button
        title="Refresh"
        aria-label="Refresh"
        variant="outlined"
        severity="secondary"
        size="small"
        @click="bt.getBacktestHistory(); fetchPbMeta();"
      >
        <i-lucide-refresh-cw />
      </Button>
    </div>
    <DataTable
      v-if="historyList.length > 0"
      size="small"
      scrollable
      scroll-height="50rem"
      show-gridlines
      :value="filteredList"
      table-style="min-width: 1200px"
      @row-click="rowClick"
    >
      <!-- Identity -->
      <Column header="Ver" field="_version" :sortable="true" frozen style="width: 50px; min-width: 50px">
        <template #body="{ data }">
          <span v-if="data._version" class="font-semibold" style="color: #10a37f">{{ data._version }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="strategy" header="Strategy" :sortable="true" frozen style="width: 100px; min-width: 100px"></Column>
      <Column header="Mode" field="_mode" :sortable="true" style="width: 65px; min-width: 65px">
        <template #body="{ data }">{{ data._mode || '—' }}</template>
      </Column>
      <Column header="TF" field="timeframe" :sortable="true" style="width: 40px; min-width: 40px">
        <template #body="{ data }"><strong>{{ data.timeframe }}</strong></template>
      </Column>
      <Column header="From" field="_from" :sortable="true" style="width: 90px; min-width: 90px">
        <template #body="{ data }">{{ data._from || '—' }}</template>
      </Column>
      <Column header="To" field="_to" :sortable="true" style="width: 90px; min-width: 90px">
        <template #body="{ data }">{{ data._to || '—' }}</template>
      </Column>

      <!-- Key metrics -->
      <Column field="_trades" :sortable="true" style="width: 65px; min-width: 65px; text-align: right">
        <template #header><span class="col-tip" title="Total number of trades executed">Trades</span></template>
        <template #body="{ data }">
          <span v-if="data._trades != null">{{ fmtComma(data._trades) }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_wins" :sortable="true" style="width: 45px; min-width: 45px; text-align: right">
        <template #header><span class="col-tip" title="Winning trades count">W</span></template>
        <template #body="{ data }">
          <span v-if="data._wins != null" style="color: #22c55e">{{ fmtComma(data._wins) }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_losses" :sortable="true" style="width: 45px; min-width: 45px; text-align: right">
        <template #header><span class="col-tip" title="Losing trades count">L</span></template>
        <template #body="{ data }">
          <span v-if="data._losses != null" style="color: #ef4444">{{ fmtComma(data._losses) }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_winrate" :sortable="true" style="width: 55px; min-width: 55px; text-align: right">
        <template #header><span class="col-tip" title="Win Rate — percentage of winning trades. Above 50% is good, above 60% is excellent">WR%</span></template>
        <template #body="{ data }">
          <span v-if="data._winrate != null">{{ fmtPct(data._winrate) }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_profit" :sortable="true" style="width: 85px; min-width: 85px; text-align: right">
        <template #header><span class="col-tip" title="Net profit in USDT">Profit</span></template>
        <template #body="{ data }">
          <span v-if="data._profit != null"
            :style="{ color: data._profit >= 0 ? '#22c55e' : '#ef4444', fontWeight: 600 }">
            {{ fmtMoney(data._profit) }}
          </span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_profitPct" :sortable="true" style="width: 65px; min-width: 65px; text-align: right">
        <template #header><span class="col-tip" title="Net profit as percentage of starting balance">Profit%</span></template>
        <template #body="{ data }">
          <span v-if="data._profitPct != null"
            :style="{ color: data._profitPct >= 0 ? '#22c55e' : '#ef4444' }">
            {{ fmtPct(data._profitPct, true) }}
          </span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_cagr" :sortable="true" style="width: 65px; min-width: 65px; text-align: right">
        <template #header><span class="col-tip" title="Compound Annual Growth Rate — annualized return. Above 20% is good, above 50% is excellent">CAGR</span></template>
        <template #body="{ data }">
          <span v-if="data._cagr != null"
            :style="{ color: data._cagr >= 0 ? '#22c55e' : '#ef4444' }">
            {{ fmtPct(data._cagr, true) }}
          </span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_dd" :sortable="true" style="width: 70px; min-width: 70px; text-align: right">
        <template #header><span class="col-tip" title="Maximum Drawdown — largest peak-to-trough decline in USDT. Lower is better">DD</span></template>
        <template #body="{ data }">
          <span v-if="data._dd != null" :style="{ color: data._dd > 0 ? '#ef4444' : undefined }">{{ data._dd > 0 ? '-' + fmtComma(Math.abs(data._dd).toFixed(0)) : '0' }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_ddPct" :sortable="true" style="width: 55px; min-width: 55px; text-align: right">
        <template #header><span class="col-tip" title="Maximum Drawdown % — largest decline as % of portfolio. Below 10% is good, below 5% is excellent">DD%</span></template>
        <template #body="{ data }">
          <span v-if="data._ddPct != null" style="color: #ef4444">-{{ (Math.abs(Number(data._ddPct)) * 100).toFixed(1) }}%</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>

      <!-- Risk metrics -->
      <Column field="_sharpe" :sortable="true" style="width: 60px; min-width: 60px; text-align: right">
        <template #header><span class="col-tip" title="Sharpe Ratio — risk-adjusted return (return / volatility). Above 1.0 is good, above 2.0 is excellent">Sharpe</span></template>
        <template #body="{ data }">
          <span v-if="data._sharpe != null">{{ fmtNum(data._sharpe) }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_sortino" :sortable="true" style="width: 65px; min-width: 65px; text-align: right">
        <template #header><span class="col-tip" title="Sortino Ratio — like Sharpe but only penalizes downside volatility. Above 1.5 is good, above 3.0 is excellent">Sortino</span></template>
        <template #body="{ data }">
          <span v-if="data._sortino != null">{{ fmtNum(data._sortino) }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_calmar" :sortable="true" style="width: 65px; min-width: 65px; text-align: right">
        <template #header><span class="col-tip" title="Calmar Ratio — annual return / max drawdown. Measures if the return is worth the pain. Above 2.0 is good, above 5.0 is excellent">Calmar</span></template>
        <template #body="{ data }">
          <span v-if="data._calmar != null">{{ fmtNum(data._calmar) }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_pf" :sortable="true" style="width: 50px; min-width: 50px; text-align: right">
        <template #header><span class="col-tip" title="Profit Factor — gross profit / gross loss. Above 1.5 is good, above 2.0 is excellent">PF</span></template>
        <template #body="{ data }">
          <span v-if="data._pf != null">{{ fmtNum(data._pf) }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_dur" :sortable="true" style="width: 70px; min-width: 70px">
        <template #header><span class="col-tip" title="Average trade duration">Dur</span></template>
        <template #body="{ data }">
          <span v-if="data._dur">{{ data._dur }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>
      <Column field="_pairs" :sortable="true" style="width: 50px; min-width: 50px; text-align: right">
        <template #header><span class="col-tip" title="Number of trading pairs">Pairs</span></template>
        <template #body="{ data }">
          <span v-if="data._pairs != null">{{ data._pairs }}</span>
          <span v-else class="opacity-30">—</span>
        </template>
      </Column>

      <!-- Notes (editable) -->
      <Column field="_notes" :sortable="true" style="width: 140px; min-width: 140px">
        <template #header><span class="col-tip" title="Click to edit notes for this backtest run">Notes</span></template>
        <template #body="{ data }">
          <div v-if="editingNoteId === data.filename" class="flex gap-1" @click.stop>
            <InputText v-model="editingNoteText" size="small" style="width: 90px" @keyup.enter="saveNote(data.filename)" @keyup.escape="editingNoteId = ''" autofocus />
            <Button size="small" severity="success" @click.stop="saveNote(data.filename)"><template #icon><i-lucide-check style="width:14px" /></template></Button>
          </div>
          <span v-else class="text-sm cursor-pointer hover:underline" @click.stop="startEditNote(data.filename, data._notes)" :title="data._notes || 'Click to add note'">
            {{ data._notes || '—' }}
          </span>
        </template>
      </Column>

      <!-- Actions -->
      <Column header="" frozen align-frozen="right" style="width: 75px; min-width: 75px">
        <template #body="{ data }">
          <div class="flex items-center gap-1">
            <Button
              v-if="bt.botFeatures.backtestDelete"
              size="small"
              title="Load this Result"
              :disabled="data.run_id in bt.backtestHistory"
              @click.stop="bt.getBacktestHistoryResult(data)"
            >
              <template #icon><i-lucide-arrow-right /></template>
            </Button>
            <Button
              v-if="bt.botFeatures.backtestDelete"
              size="small"
              severity="secondary"
              title="Delete this Result"
              :disabled="data.run_id in bt.backtestHistory"
              @click.stop="deleteBacktestResult(data)"
            >
              <template #icon><i-lucide-trash-2 /></template>
            </Button>
          </div>
        </template>
      </Column>
    </DataTable>
    <p v-else class="text-center opacity-50 mt-4">No backtest results found.</p>
  </div>
  <MessageBox ref="msgBox" />
</template>

